-- ============================================
-- Голос из архива — Тестовые данные (seed.sql)
-- Совместимо с SQLite и PostgreSQL
-- ============================================

-- Таблица: репрессированные
CREATE TABLE IF NOT EXISTS persons (
    id INTEGER PRIMARY KEY,
    full_name TEXT NOT NULL,
    birth_year INTEGER,
    death_year INTEGER,
    region TEXT,
    district TEXT,
    occupation TEXT,
    charge TEXT,
    arrest_date TEXT,
    sentence TEXT,
    sentence_date TEXT,
    rehabilitation_date TEXT,
    biography TEXT,
    source TEXT,
    status TEXT DEFAULT 'pending',
    created_at TEXT DEFAULT (datetime('now'))
);

-- Таблица: документы
CREATE TABLE IF NOT EXISTS documents (
    id INTEGER PRIMARY KEY,
    filename TEXT NOT NULL,
    content TEXT,
    uploaded_at TEXT DEFAULT (datetime('now'))
);

-- Таблица: чанки (фрагменты документов)
CREATE TABLE IF NOT EXISTS chunks (
    id INTEGER PRIMARY KEY,
    document_id INTEGER REFERENCES documents(id),
    chunk_text TEXT NOT NULL,
    chunk_index INTEGER
);

-- ============================================
-- Вставка карточек репрессированных
-- ============================================

INSERT INTO persons (id, full_name, birth_year, death_year, region, district, occupation, charge, arrest_date, sentence, sentence_date, rehabilitation_date, biography, source, status) VALUES
(1, 'Байтемиров Асан Жумабекович', 1899, 1937, 'Чүйская область', 'Кара-Балта', 'Учитель начальной школы', 'Контрреволюционная агитация (ст. 58-10)', '1937-08-12', 'Расстрел', '1937-11-03', '1958-04-15', 'Родился в селе Ак-Башат. Окончил педагогические курсы в Пишпеке в 1922 году. Преподавал в начальной школе, обучал детей грамоте на кыргызском языке. Арестован по доносу соседа. Обвинён в антисоветской агитации среди учеников. Расстрелян через три месяца после ареста. Реабилитирован посмертно в 1958 году.', 'Архив ГКНБ КР, фонд 10, дело 4412', 'verified'),
(2, 'Сыдыкова Бурул Токтогуловна', 1905, 1943, 'Ошская область', 'Ош', 'Врач, заведующая фельдшерским пунктом', 'Шпионаж в пользу иностранного государства (ст. 58-6)', '1938-03-20', '10 лет ИТЛ', '1938-07-14', '1956-09-22', 'Родилась в Оше. Одна из первых кыргызских женщин-врачей. Окончила медицинский техникум во Фрунзе. Работала в районной больнице, лечила жителей окрестных сёл. Арестована по обвинению в шпионаже — основанием стали письма от родственников в Китае. Отправлена в лагерь в Казахстане, где скончалась от тифа в 1943 году.', 'Архив ГКНБ КР, фонд 10, дело 5581', 'verified'),
(3, 'Токтогулов Качкынбай Асанович', 1892, 1938, 'Иссык-Кульская область', 'Каракол', 'Председатель колхоза', 'Участие в контрреволюционной организации (ст. 58-11)', '1937-10-05', 'Расстрел', '1938-01-18', '1957-06-30', 'Родился в селе Тамга. Участник Гражданской войны. В 1930-е годы возглавлял колхоз «Кызыл Жылдыз». Выступал против форсированной коллективизации, защищая интересы односельчан. Арестован вместе с четырьмя другими председателями. Расстрелян в Караколе.', 'Архив ГКНБ КР, фонд 10, дело 3318', 'verified'),
(4, 'Касымов Абдыкерим Маматович', 1910, 1942, 'Джалал-Абадская область', 'Джалал-Абад', 'Журналист, редактор районной газеты', 'Антисоветская пропаганда (ст. 58-10)', '1938-06-10', '8 лет ИТЛ', '1938-10-25', '1957-03-11', 'Родился в Джалал-Абаде. Окончил рабфак во Фрунзе. Работал корреспондентом, затем редактором районной газеты. Публиковал статьи о трудностях колхозной жизни. Арестован после критической статьи о невыполнении плана. Погиб в лагере на Колыме.', 'Архив ГКНБ КР, фонд 10, дело 6723', 'verified'),
(5, 'Ибраимов Турдубай Сатылганович', 1895, 1937, 'Нарынская область', 'Нарын', 'Бывший манап, скотовод', 'Контрреволюционная деятельность (ст. 58-2)', '1937-07-15', 'Расстрел', '1937-09-28', '1959-01-20', 'Родился в урочище Сон-Куль. До революции принадлежал к влиятельному роду. После коллективизации лишён имущества, работал чабаном в колхозе. Арестован как «бывший манап» и обвинён в подготовке восстания. Расстрелян в Нарыне. Семья выслана в Казахстан.', 'Архив ГКНБ КР, фонд 10, дело 2290', 'verified'),
(6, 'Жумагулов Орозбек Тайлакович', 1903, 1944, 'Таласская область', 'Талас', 'Агроном', 'Вредительство (ст. 58-7)', '1938-04-02', '10 лет ИТЛ', '1938-08-17', '1956-12-05', 'Родился в селе Кызыл-Адыр. Окончил сельскохозяйственный техникум. Работал агрономом в Таласском районе. Обвинён во вредительстве после неурожая. Погиб в лагере в Магаданской области.', 'Архив ГКНБ КР, фонд 10, дело 4901', 'verified'),
(7, 'Атамбаева Айчурок Керимовна', 1912, NULL, 'Чүйская область', 'Фрунзе', 'Учительница, поэтесса', 'Связь с врагом народа (ст. 58-12)', '1938-01-15', '5 лет ссылки', '1938-05-20', '1955-11-10', 'Родилась во Фрунзе. Преподавала кыргызский язык и литературу. Писала стихи. Арестована как жена «врага народа». Отправлена в ссылку в Сибирь. Вернулась в 1943 году.', 'Архив ГКНБ КР, фонд 10, дело 5120', 'verified'),
(8, 'Маматов Эсенгул Кадырович', 1888, 1937, 'Ошская область', 'Узген', 'Мулла, духовный деятель', 'Антисоветская агитация на религиозной почве (ст. 58-10)', '1937-06-22', 'Расстрел', '1937-08-30', '1989-05-14', 'Родился в Узгене. Духовный лидер общины. Продолжал тайно проводить религиозные обряды после закрытия мечетей. Расстрелян. Реабилитирован только в 1989 году.', 'Архив ГКНБ КР, фонд 10, дело 1847', 'verified'),
(9, 'Чоткараев Сүйүнбай Болотович', 1907, 1945, 'Иссык-Кульская область', 'Балыкчы', 'Железнодорожный рабочий', 'Саботаж (ст. 58-14)', '1941-12-10', '10 лет ИТЛ', '1942-02-18', '1957-08-25', 'Родился в Балыкчы. Работал обходчиком путей. Обвинён в саботаже после схода вагона с рельсов. Погиб в лагере в 1945 году.', 'Архив ГКНБ КР, фонд 10, дело 7845', 'verified'),
(10, 'Бекбоев Осмон Жапарович', 1901, 1938, 'Нарынская область', 'Ат-Башы', 'Ветеринар', 'Вредительство в животноводстве (ст. 58-7)', '1937-11-20', 'Расстрел', '1938-02-14', '1958-07-03', 'Родился в районе Ат-Башы. Единственный ветеринар на весь район. Обвинён во вредительстве после массового падежа скота. Расстрелян.', 'Архив ГКНБ КР, фонд 10, дело 3567', 'verified'),
(11, 'Алымкулов Курман Сатыбалдиевич', 1896, 1938, 'Джалал-Абадская область', 'Токтогул', 'Сказитель (манасчи)', 'Националистическая пропаганда (ст. 58-10)', '1937-09-14', 'Расстрел', '1938-01-07', '1957-12-19', 'Известный манасчи. Обвинён в националистической пропаганде через исполнение эпоса «Манас». Расстрелян.', 'Архив ГКНБ КР, фонд 10, дело 2934', 'verified'),
(12, 'Тургунбаева Канышай Абдылдаевна', 1915, NULL, 'Баткенская область', 'Баткен', 'Колхозница', 'Хищение социалистической собственности (ст. 7-35)', '1947-10-08', '7 лет ИТЛ', '1947-12-15', '1954-06-20', 'Работала в колхозе на хлопковых полях. Осуждена за сбор оставшегося зерна для голодающих детей. Отбыла 7 лет.', 'Архив ГКНБ КР, фонд 10, дело 9214', 'verified'),
(13, 'Исмаилов Ракмат Назарович', 1908, 1938, 'Ошская область', 'Кара-Суу', 'Торговец, владелец лавки', 'Спекуляция и контрреволюция (ст. 58-10, 107)', '1937-12-05', 'Расстрел', '1938-03-20', '1958-02-28', 'Владел лавкой на базаре. Обвинён в спекуляции и связях с контрреволюционерами. Расстрелян.', 'Архив ГКНБ КР, фонд 10, дело 6102', 'verified'),
(14, 'Джунушалиев Мамбеткали Сагынбаевич', 1900, 1937, 'Чүйская область', 'Токмок', 'Партийный работник, секретарь райкома', 'Участие в антисоветском заговоре (ст. 58-8, 58-11)', '1937-06-28', 'Расстрел', '1937-10-12', '1956-04-17', 'Активный участник установления советской власти. Секретарь Чуйского райкома. Расстрелян в ходе чистки партийных кадров.', 'Архив ГКНБ КР, фонд 10, дело 1523', 'verified'),
(15, 'Абдуллаев Хасан Юсупович', 1885, 1938, 'Ошская область', 'Ноокат', 'Кустарь, ремесленник', 'Антисоветская деятельность (ст. 58-10)', '1937-08-18', 'Расстрел', '1938-01-25', '1959-03-10', 'Занимался изготовлением седел. Обвинён в антисоветских настроениях. Расстрелян в Оше.', 'Архив ГКНБ КР, фонд 10, дело 4478', 'verified'),
(16, 'Калыков Байыш Темирович', 1911, 1953, 'Таласская область', 'Кара-Буура', 'Учитель истории', 'Антисоветская пропаганда (ст. 58-10)', '1949-03-12', '25 лет ИТЛ', '1949-07-08', '1956-10-30', 'Преподавал историю. Арестован за рассказы о восстании 1916 года. Скончался в заключении.', 'Архив ГКНБ КР, фонд 10, дело 8832', 'verified'),
